                                                                                                                                                                                                private void TestDatabaseConnection()
                                                                                                                                                                                                {
                                                                                                                                                                                                try
                                                                                                                                                                                                {
                                                                                                                                                                                                using MySqlConnection conn = new MySqlConnection(connectionString);
                                                                                                                                                                                                conn.Open();
                                                                                                                                                                                                InitializeTasksTable(conn);
                                                                                                                                                                                                dbAvailable = true;
                                                                                                                                                                                                LogActivity("Database connected successfully", "System");
                                                                                                                                                                                                }
                                                                                                                                                                                                catch (Exception ex)
                                                                                                                                                                                                {
                                                                                                                                                                                                dbAvailable = false;
                                                                                                                                                                                                LogActivity("Database unavailable — using in-memory storage. Error: " + ex.Message, "System");
                                                                                                                                                                                                }
                                                                                                                                                                                                }

                                                                                                                                                                                                private void InitializeTasksTable(MySqlConnection conn)
                                                                                                                                                                                                {
                                                                                                                                                                                                string createTable = @"
                                                                                                                                                                                                CREATE TABLE IF NOT EXISTS tasks (
                                                                                                                                                                                                id INT AUTO_INCREMENT PRIMARY KEY,
                                                                                                                                                                                                title VARCHAR(255) NOT NULL,
                                                                                                                                                                                                description TEXT,
                                                                                                                                                                                                reminder_days INT DEFAULT 0,
                                                                                                                                                                                                reminder_date DATETIME,
                                                                                                                                                                                                created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                                                                                                                                                                                                is_completed BOOLEAN DEFAULT FALSE,
                                                                                                                                                                                                user_name VARCHAR(100)
                                                                                                                                                                                                )";
                                                                                                                                                                                                using MySqlCommand cmd = new MySqlCommand(createTable, conn);
                                                                                                                                                                                                cmd.ExecuteNonQuery();
                                                                                                                                                                                                }

                                                                                                                                                                                                private int AddTaskToDatabase(string title, string description, int reminderDays)
                                                                                                                                                                                                {
                                                                                                                                                                                                if (dbAvailable)
                                                                                                                                                                                                {
                                                                                                                                                                                                try
                                                                                                                                                                                                {
                                                                                                                                                                                                using MySqlConnection conn = new MySqlConnection(connectionString);
                                                                                                                                                                                                conn.Open();
                                                                                                                                                                                                string query = @"INSERT INTO tasks (title, description, reminder_days, reminder_date, user_name)
                                                                                                                                                                                                VALUES (@title, @desc, @days, @date, @user);
                                                                                                                                                                                                SELECT LAST_INSERT_ID();";
                                                                                                                                                                                                using MySqlCommand cmd = new MySqlCommand(query, conn);
                                                                                                                                                                                                cmd.Parameters.AddWithValue("@title", title);
                                                                                                                                                                                                cmd.Parameters.AddWithValue("@desc", description ?? "");
                                                                                                                                                                                                cmd.Parameters.AddWithValue("@days", reminderDays);
                                                                                                                                                                                                cmd.Parameters.AddWithValue("@date",
reminderDays > 0 ? (object)DateTime.Now.AddDays(reminderDays) : DBNull.Value);
                                                                                                                                                                                                    cmd.Parameters.AddWithValue("@user", userName);
                                                                                                                                                                                                    return Convert.ToInt32(cmd.ExecuteScalar());
                                                                                                                                                                                                    }
                                                                                                                                                                                                    catch (Exception ex)
                                                                                                                                                                                                    {
                                                                                                                                                                                                    LogActivity("Database add task failed: " + ex.Message, "System");
                                                                                                                                                                                                    }
                                                                                                                                                                                                    }
                                                                                                                                                                                                    var task = new CyberTask
                                                                                                                                                                                                    {
                                                                                                                                                                                                    Id = nextTaskId++,
                                                                                                                                                                                                    Title = title,
                                                                                                                                                                                                    Description = description ?? "",
                                                                                                                                                                                                    ReminderDays = reminderDays,
ReminderDate = reminderDays > 0 ? DateTime.Now.AddDays(reminderDays) : null,
                                                                                                                                                                                                        CreatedAt = DateTime.Now,
                                                                                                                                                                                                        IsCompleted = false
                                                                                                                                                                                                        };
                                                                                                                                                                                                        inMemoryTasks.Add(task);
                                                                                                                                                                                                        return task.Id;
                                                                                                                                                                                                        }

                                                                                                                                                                                                        private List<CyberTask> GetAllTasksFromDatabase()
                                                                                                                                                                                                            {
                                                                                                                                                                                                            if (dbAvailable)
                                                                                                                                                                                                            {
                                                                                                                                                                                                            try
                                                                                                                                                                                                            {
                                                                                                                                                                                                            var tasks = new List<CyberTask>();
                                                                                                                                                                                                                using MySqlConnection conn = new MySqlConnection(connectionString);
                                                                                                                                                                                                                conn.Open();
                                                                                                                                                                                                                using MySqlCommand cmd = new MySqlCommand("SELECT * FROM tasks ORDER BY created_at DESC", conn);
                                                                                                                                                                                                                using MySqlDataReader reader = cmd.ExecuteReader();
                                                                                                                                                                                                                while (reader.Read())
                                                                                                                                                                                                                {
                                                                                                                                                                                                                tasks.Add(new CyberTask
                                                                                                                                                                                                                {
                                                                                                                                                                                                                Id = reader.GetInt32("id"),
                                                                                                                                                                                                                Title = reader.GetString("title"),
                                                                                                                                                                                                                Description = reader.IsDBNull(reader.GetOrdinal("description")) ? "" : reader.GetString("description"),
                                                                                                                                                                                                                ReminderDays = reader.IsDBNull(reader.GetOrdinal("reminder_days")) ? 0 : reader.GetInt32("reminder_days"),
                                                                                                                                                                                                                ReminderDate = reader.IsDBNull(reader.GetOrdinal("reminder_date")) ? null : reader.GetDateTime("reminder_date"),
                                                                                                                                                                                                                CreatedAt = reader.GetDateTime("created_at"),
                                                                                                                                                                                                                IsCompleted = reader.GetBoolean("is_completed")
                                                                                                                                                                                                                });
                                                                                                                                                                                                                }
                                                                                                                                                                                                                return tasks;
                                                                                                                                                                                                                }
                                                                                                                                                                                                                catch (Exception ex)
                                                                                                                                                                                                                {
                                                                                                                                                                                                                LogActivity("Database get tasks failed: " + ex.Message, "System");
                                                                                                                                                                                                                }
                                                                                                                                                                                                                }
return inMemoryTasks.OrderByDescending(t => t.CreatedAt).ToList();
                                                                                                                                                                                                                    }

                                                                                                                                                                                                                    private void DeleteTaskFromDatabase(int taskId)
                                                                                                                                                                                                                    {
                                                                                                                                                                                                                    if (dbAvailable)
                                                                                                                                                                                                                    {
                                                                                                                                                                                                                    try
                                                                                                                                                                                                                    {
                                                                                                                                                                                                                    using MySqlConnection conn = new MySqlConnection(connectionString);
                                                                                                                                                                                                                    conn.Open();
                                                                                                                                                                                                                    using MySqlCommand cmd = new MySqlCommand("DELETE FROM tasks WHERE id = @id", conn);
                                                                                                                                                                                                                    cmd.Parameters.AddWithValue("@id", taskId);
                                                                                                                                                                                                                    cmd.ExecuteNonQuery();
                                                                                                                                                                                                                    return;
                                                                                                                                                                                                                    }
                                                                                                                                                                                                                    catch (Exception ex)
                                                                                                                                                                                                                    {
                                                                                                                                                                                                                    LogActivity("Database delete task failed: " + ex.Message, "System");
                                                                                                                                                                                                                    }
                                                                                                                                                                                                                    }
var t = inMemoryTasks.FirstOrDefault(x => x.Id == taskId);
                                                                                                                                                                                                                        if (t != null) inMemoryTasks.Remove(t);
                                                                                                                                                                                                                        }

                                                                                                                                                                                                                        private void CompleteTaskInDatabase(int taskId)
                                                                                                                                                                                                                        {
                                                                                                                                                                                                                        if (dbAvailable)
                                                                                                                                                                                                                        {
                                                                                                                                                                                                                        try
                                                                                                                                                                                                                        {
                                                                                                                                                                                                                        using MySqlConnection conn = new MySqlConnection(connectionString);
                                                                                                                                                                                                                        conn.Open();
                                                                                                                                                                                                                        using MySqlCommand cmd = new MySqlCommand("UPDATE tasks SET is_completed = TRUE WHERE id = @id", conn);
                                                                                                                                                                                                                        cmd.Parameters.AddWithValue("@id", taskId);
                                                                                                                                                                                                                        cmd.ExecuteNonQuery();
                                                                                                                                                                                                                        return;
                                                                                                                                                                                                                        }
                                                                                                                                                                                                                        catch (Exception ex)
                                                                                                                                                                                                                        {
                                                                                                                                                                                                                        LogActivity("Database complete task failed: " + ex.Message, "System");
                                                                                                                                                                                                                        }
                                                                                                                                                                                                                        }
var t = inMemoryTasks.FirstOrDefault(x => x.Id == taskId);
                                                                                                                                                                                                                            if (t != null) t.IsCompleted = true;
                                                                                                                                                                                                                            }

private void SendButton_Click(object sender, RoutedEventArgs e) => ProcessUserInput();

                                                                                                                                                                                                                                private void InputBox_KeyDown(object sender, System.Windows.Input.KeyEventArgs e)
                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                if (e.Key == System.Windows.Input.Key.Enter) ProcessUserInput();
                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                private void ProcessUserInput()
                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                string input = InputBox.Text.Trim();
                                                                                                                                                                                                                                if (string.IsNullOrWhiteSpace(input)) return;

                                                                                                                                                                                                                                ChatBox.AppendText("You: " + input + Environment.NewLine + Environment.NewLine);
                                                                                                                                                                                                                                InputBox.Clear();

                                                                                                                                                                                                                                if (waitingForName)
                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                userName = input;
                                                                                                                                                                                                                                waitingForName = false;
                                                                                                                                                                                                                                LogActivity("User registered: " + userName, "System");
                                                                                                                                                                                                                                responseHandler(
                                                                                                                                                                                                                                "Nice to meet you, " + userName + "!\n\n" +
                                                                                                                                                                                                                                "I can help you with:\n" +
                                                                                                                                                                                                                                "• Cybersecurity topics — passwords, phishing, malware, VPNs, encryption, ransomware, firewall, safe browsing\n" +
                                                                                                                                                                                                                                "• Task management — type 'add task' or 'remind me to...'\n" +
                                                                                                                                                                                                                                "• Quiz game — type 'start quiz'\n" +
                                                                                                                                                                                                                                "• Activity log — type 'show activity log'\n\n" +
                                                                                                                                                                                                                                "What would you like to know?");
                                                                                                                                                                                                                                ChatBox.ScrollToEnd();
                                                                                                                                                                                                                                return;
                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                if (taskState != TaskConversationState.None)
                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                HandleTaskConversation(input);
                                                                                                                                                                                                                                ChatBox.ScrollToEnd();
                                                                                                                                                                                                                                return;
                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                string reply = GetResponse(input);
                                                                                                                                                                                                                                responseHandler(reply);
                                                                                                                                                                                                                                ChatBox.ScrollToEnd();
                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                private string GetResponse(string input)
                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                string lower = input.ToLower().Trim();

                                                                                                                                                                                                                                if (lower.Contains("hello") || lower.Contains("hi ") || lower == "hi" || lower.Contains("hey"))
                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                LogActivity("User greeted the bot", "NLP");
                                                                                                                                                                                                                                return "Hello " + userName + "! How can I help you stay safe online?\n" +
                                                                                                                                                                                                                                "Ask me about passwords, phishing, malware, ransomware, VPNs, encryption, firewalls, or safe browsing.";
                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                if (lower.Contains("thank"))
                                                                                                                                                                                                                                return "You're welcome, " + userName + "! Stay safe online.";
                                                                                                                                                                                                                                if (lower.Contains("bye") || lower.Contains("goodbye"))
                                                                                                                                                                                                                                return "Goodbye " + userName + "! Stay secure out there.";
                                                                                                                                                                                                                                if (lower.Contains("worried") || lower.Contains("scared") || lower.Contains("anxious") || lower.Contains("concerned"))
                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                LogActivity("User expressed concern", "NLP");
                                                                                                                                                                                                                                return "It's completely normal to feel that way, " + userName + ". Awareness is your best protection. " + GetRandom("scam");
                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                if (lower.Contains("interested in privacy"))
                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                userMemory["interest"] = "privacy";
                                                                                                                                                                                                                                LogActivity("User interested in privacy", "NLP");
                                                                                                                                                                                                                                return "Got it! I will remember that. " + GetRandom("privacy");
                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                if (lower.Contains("interested in phishing"))
                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                userMemory["interest"] = "phishing";
                                                                                                                                                                                                                                LogActivity("User interested in phishing", "NLP");
                                                                                                                                                                                                                                return "Got it! I will remember that. " + GetRandom("phishing");
                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                if (MatchesAnyKeyword(lower, addTaskKeywords))
                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                string inlineTitle = ExtractInlineTitle(lower);
                                                                                                                                                                                                                                if (!string.IsNullOrEmpty(inlineTitle)) return StartTaskCreationWithTitle(inlineTitle);
                                                                                                                                                                                                                                return StartTaskCreation();
                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                if (MatchesAnyKeyword(lower, viewTaskKeywords)) return ShowTasksInChat();
                                                                                                                                                                                                                                if (MatchesAnyKeyword(lower, startQuizKeywords))
                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                LogActivity("User started quiz via chat", "Quiz");
                                                                                                                                                                                                                                StartQuiz();
                                                                                                                                                                                                                                return "Starting the quiz! Switch to the Quiz Game tab. Good luck, " + userName + "!";
                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                if (MatchesAnyKeyword(lower, showLogKeywords)) return ShowActivityLogInChat();
                                                                                                                                                                                                                                if (lower.Contains("tell me more") || lower.Contains("another tip") || lower.Contains("more info"))
                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                if (!string.IsNullOrEmpty(lastTopic))
                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                LogActivity("User requested more on: " + lastTopic, "NLP");
                                                                                                                                                                                                                                return GetRandom(lastTopic);
                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                return "Please ask about a topic first — try passwords, phishing, malware, or VPNs.";
                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                foreach (var item in keywords)
                                                                                                                                                                                                                                foreach (var keyword in item.Value)
                                                                                                                                                                                                                                if (lower.Contains(keyword))
                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                lastTopic = item.Key;
                                                                                                                                                                                                                                LogActivity("User asked about: " + item.Key, "Topic");
                                                                                                                                                                                                                                return GetRandom(item.Key);
                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                if (userMemory.ContainsKey("interest"))
                                                                                                                                                                                                                                return "Since you are interested in " + userMemory["interest"] + ", here is a tip: " + GetRandom(userMemory["interest"]);

                                                                                                                                                                                                                                LogActivity("Unrecognised input", "NLP");
                                                                                                                                                                                                                                return "I did not quite understand that. Could you rephrase?\n" +
                                                                                                                                                                                                                                "Try: passwords, phishing, malware, ransomware, VPN, encryption, firewall, safe browsing\n" +
                                                                                                                                                                                                                                "Or type: 'add task'  |  'start quiz'  |  'show activity log'";
                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                private bool MatchesAnyKeyword(string input, List<string> keywordList)
                                                                                                                                                                                                                                    {
                                                                                                                                                                                                                                    foreach (string kw in keywordList)
                                                                                                                                                                                                                                    if (input.Contains(kw)) return true;
                                                                                                                                                                                                                                    return false;
                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                    private string ExtractInlineTitle(string lower)
                                                                                                                                                                                                                                    {
                                                                                                                                                                                                                                    string[] patterns = { "remind me to ", "can you remind me to ", "set a reminder to ", "add a task to ", "add task to ", "create task to ", "add a task - ", "add task - " };
                                                                                                                                                                                                                                    foreach (string pattern in patterns)
                                                                                                                                                                                                                                    {
                                                                                                                                                                                                                                    int idx = lower.IndexOf(pattern);
if (idx >= 0)
                                                                                                                                                                                                                                        {
                                                                                                                                                                                                                                        string extracted = lower.Substring(idx + pattern.Length).Trim();
if (!string.IsNullOrWhiteSpace(extracted) && extracted.Length > 0)
                                                                                                                                                                                                                                            return char.ToUpper(extracted[0]) + extracted.Substring(1);
                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                            return "";
                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                            private string StartTaskCreation()
                                                                                                                                                                                                                                            {
                                                                                                                                                                                                                                            taskState = TaskConversationState.WaitingForTitle;
                                                                                                                                                                                                                                            LogActivity("User started task creation", "Task");
                                                                                                                                                                                                                                            return "Sure! Let us add a new cybersecurity task.\nWhat is the title?\n(e.g. 'Enable two-factor authentication', 'Review privacy settings')";
                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                            private string StartTaskCreationWithTitle(string title)
                                                                                                                                                                                                                                            {
                                                                                                                                                                                                                                            pendingTaskTitle = title;
                                                                                                                                                                                                                                            taskState = TaskConversationState.WaitingForDescription;
                                                                                                                                                                                                                                            LogActivity("Task title auto-extracted: " + title, "Task");
                                                                                                                                                                                                                                            return "Task title set to: '" + title + "'\nPlease enter a description (or type 'skip'):";
                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                            private void HandleTaskConversation(string input)
                                                                                                                                                                                                                                            {
                                                                                                                                                                                                                                            switch (taskState)
                                                                                                                                                                                                                                            {
                                                                                                                                                                                                                                            case TaskConversationState.WaitingForTitle:
                                                                                                                                                                                                                                            pendingTaskTitle = input;
                                                                                                                                                                                                                                            taskState = TaskConversationState.WaitingForDescription;
                                                                                                                                                                                                                                            responseHandler("Got it! Enter a description for '" + pendingTaskTitle + "' (or type 'skip'):");
                                                                                                                                                                                                                                            break;

                                                                                                                                                                                                                                            case TaskConversationState.WaitingForDescription:
                                                                                                                                                                                                                                            pendingTaskDescription = input.ToLower() == "skip" ? "" : input;
                                                                                                                                                                                                                                            taskState = TaskConversationState.WaitingForReminder;
                                                                                                                                                                                                                                            responseHandler("Would you like a reminder?\nEnter number of days (e.g. '3'), or '0' for no reminder:");
                                                                                                                                                                                                                                            break;

                                                                                                                                                                                                                                            case TaskConversationState.WaitingForReminder:
                                                                                                                                                                                                                                            if (!int.TryParse(input, out int days) || days < 0)
                                                                                                                                                                                                                                              {
                                                                                                                                                                                                                                              responseHandler("Please enter a valid number like '3', or '0' for no reminder:");
                                                                                                                                                                                                                                              return;
                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                              AddTaskToDatabase(pendingTaskTitle, pendingTaskDescription, days);
                                                                                                                                                                                                                                              string reminderMsg = days > 0
                                                                                                                                                                                                                                                ? "Reminder set for " + days + " day(s) — Due: " + DateTime.Now.AddDays(days).ToString("yyyy-MM-dd")
                                                                                                                                                                                                                                                : "No reminder set.";
                                                                                                                                                                                                                                                responseHandler(
                                                                                                                                                                                                                                                "Task added!\n" +
                                                                                                                                                                                                                                                "   Title: " + pendingTaskTitle + "\n" +
                                                                                                                                                                                                                                                "   Description: " + (string.IsNullOrEmpty(pendingTaskDescription) ? "N/A" : pendingTaskDescription) + "\n" +
                                                                                                                                                                                                                                                "   " + reminderMsg + "\n\n" +
                                                                                                                                                                                                                                                "View all tasks in the Task Assistant tab or type 'view tasks'.");
                                                                                                                                                                                                                                              LogActivity("Task added: '" + pendingTaskTitle + "'" + (days > 0 ? " (Reminder: " + days + " days)" : " (No reminder)"), "Task");
                                                                                                                                                                                                                                                    taskState = TaskConversationState.None;
                                                                                                                                                                                                                                                    pendingTaskTitle = "";
                                                                                                                                                                                                                                                    pendingTaskDescription = "";
                                                                                                                                                                                                                                                    RefreshTaskList();
                                                                                                                                                                                                                                                    break;
                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                    private string ShowTasksInChat()
                                                                                                                                                                                                                                                    {
                                                                                                                                                                                                                                                    var tasks = GetAllTasksFromDatabase();
                                                                                                                                                                                                                                                    if (tasks.Count == 0)
                                                                                                                                                                                                                                                    {
                                                                                                                                                                                                                                                    LogActivity("User viewed tasks — none found", "Task");
                                                                                                                                                                                                                                                    return "You have no tasks yet, " + userName + ". Type 'add task' to create one!";
                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                    LogActivity("User viewed tasks (" + tasks.Count + " found)", "Task");
                                                                                                                                                                                                                                                    string result = "Here are your tasks, " + userName + ":\n\n";
                                                                                                                                                                                                                                                    int c = 1;
                                                                                                                                                                                                                                                    foreach (var task in tasks.Take(5))
                                                                                                                                                                                                                                                    {
                                                                                                                                                                                                                                                    result += c + ". " + (task.IsCompleted ? "✅" : "⬜") + " " + task.Title;
                                                                                                                                                                                                                                              if (task.ReminderDays > 0) result += " (Reminder: " + task.ReminderDays + " days)";
                                                                                                                                                                                                                                                        result += "\n";
                                                                                                                                                                                                                                                        c++;
                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                              if (tasks.Count > 5) result += "\n...and " + (tasks.Count - 5) + " more in the Task tab!";
                                                                                                                                                                                                                                                            return result;
                                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                            private void RefreshTaskList()
                                                                                                                                                                                                                                                            {
                                                                                                                                                                                                                                                            TaskList.ItemsSource = null;
                                                                                                                                                                                                                                                            TaskList.ItemsSource = GetAllTasksFromDatabase();
                                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                            private void AddTaskButton_Click(object sender, RoutedEventArgs e)
                                                                                                                                                                                                                                                            {
                                                                                                                                                                                                                                                            string title = TaskTitleBox.Text.Trim();
                                                                                                                                                                                                                                                            string desc = TaskDescBox.Text.Trim();
                                                                                                                                                                                                                                                            int.TryParse(TaskReminderBox.Text.Trim(), out int days);
                                                                                                                                                                                                                                                            if (string.IsNullOrWhiteSpace(title))
                                                                                                                                                                                                                                                            {
                                                                                                                                                                                                                                                            MessageBox.Show("Please enter a task title.", "Warning", MessageBoxButton.OK, MessageBoxImage.Warning);
                                                                                                                                                                                                                                                            return;
                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                            AddTaskToDatabase(title, desc, days);
                                                                                                                                                                                                                                                            LogActivity("Task added via UI: '" + title + "'", "Task");
                                                                                                                                                                                                                                              responseHandler("Task '" + title + "' added!" + (days > 0 ? " Reminder: " + days + " day(s)." : ""));
                                                                                                                                                                                                                                                                TaskTitleBox.Clear();
                                                                                                                                                                                                                                                                TaskDescBox.Clear();
                                                                                                                                                                                                                                                                TaskReminderBox.Text = "0";
                                                                                                                                                                                                                                                                RefreshTaskList();
                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                private void RefreshTasksButton_Click(object sender, RoutedEventArgs e)
                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                RefreshTaskList();
                                                                                                                                                                                                                                                                LogActivity("User refreshed task list", "Task");
                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                private void CompleteTaskButton_Click(object sender, RoutedEventArgs e)
                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                if (sender is Button btn && btn.Tag is int taskId)
                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                CompleteTaskInDatabase(taskId);
                                                                                                                                                                                                                                                                LogActivity("Task completed (ID: " + taskId + ")", "Task");
                                                                                                                                                                                                                                                                responseHandler("Task completed! Well done, " + userName + "!");
                                                                                                                                                                                                                                                                RefreshTaskList();
                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                private void DeleteTaskButton_Click(object sender, RoutedEventArgs e)
                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                if (sender is Button btn && btn.Tag is int taskId)
                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                DeleteTaskFromDatabase(taskId);
                                                                                                                                                                                                                                                                LogActivity("Task deleted (ID: " + taskId + ")", "Task");
                                                                                                                                                                                                                                                                responseHandler("Task deleted.");
                                                                                                                                                                                                                                                                RefreshTaskList();
                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                private void StartQuiz()
                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                currentQuestionIndex = 0;
                                                                                                                                                                                                                                                                quizScore = 0;
                                                                                                                                                                                                                                                                QuizStartPanel.Visibility = Visibility.Collapsed;
                                                                                                                                                                                                                                                                QuizResultsPanel.Visibility = Visibility.Collapsed;
                                                                                                                                                                                                                                                                QuizPanel.Visibility = Visibility.Visible;
                                                                                                                                                                                                                                                                DisplayQuestion();
                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                private void StartQuizButton_Click(object sender, RoutedEventArgs e)
                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                LogActivity("Quiz started", "Quiz");
                                                                                                                                                                                                                                                                StartQuiz();
                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                private void DisplayQuestion()
                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                              if (currentQuestionIndex >= quizQuestions.Count) { ShowQuizResults(); return; }

                                                                                                                                                                                                                                                                    QuizQuestion q = quizQuestions[currentQuestionIndex];
                                                                                                                                                                                                                                                                    QuizProgress.Text = "Question " + (currentQuestionIndex + 1) + " of " + quizQuestions.Count;
                                                                                                                                                                                                                                                                    QuizScoreLabel.Text = "Score: " + quizScore + "/" + quizQuestions.Count;
                                                                                                                                                                                                                                                                    QuizQuestionType.Text = "Type: " + q.Type;
                                                                                                                                                                                                                                                                    QuizQuestionText.Text = q.Question;
                                                                                                                                                                                                                                                                    QuizOptionsPanel.Children.Clear();

                                                                                                                                                                                                                                                                    for (int i = 0; i < q.Options.Count; i++)
                                                                                                                                                                                                                                                                      {
                                                                                                                                                                                                                                                                      Button btn = new Button
                                                                                                                                                                                                                                                                      {
                                                                                                                                                                                                                                                                      Content = q.Options[i],
                                                                                                                                                                                                                                                                      Margin = new Thickness(0, 5, 0, 5),
                                                                                                                                                                                                                                                                      Padding = new Thickness(10),
                                                                                                                                                                                                                                                                      FontSize = 13,
                                                                                                                                                                                                                                                                      HorizontalAlignment = HorizontalAlignment.Stretch,
                                                                                                                                                                                                                                                                      HorizontalContentAlignment = HorizontalAlignment.Left,
                                                                                                                                                                                                                                                                      Background = new SolidColorBrush(Color.FromRgb(0x1A, 0x1A, 0x2A)),
                                                                                                                                                                                                                                                                      Foreground = new SolidColorBrush(Colors.White),
                                                                                                                                                                                                                                                                      BorderBrush = new SolidColorBrush(Color.FromRgb(0x00, 0xB4, 0x8A)),
                                                                                                                                                                                                                                                                      Tag = i
                                                                                                                                                                                                                                                                      };
                                                                                                                                                                                                                                                                      btn.Click += QuizOption_Click;
                                                                                                                                                                                                                                                                      QuizOptionsPanel.Children.Add(btn);
                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                      QuizFeedbackBorder.Visibility = Visibility.Collapsed;
                                                                                                                                                                                                                                                                      QuizNextButton.Visibility = Visibility.Collapsed;
                                                                                                                                                                                                                                                                      }

                                                                                                                                                                                                                                                                      private void QuizOption_Click(object sender, RoutedEventArgs e)
                                                                                                                                                                                                                                                                      {
                                                                                                                                                                                                                                                                      if (QuizNextButton.Visibility == Visibility.Visible) return;
                                                                                                                                                                                                                                                                      Button clicked = (Button)sender;
                                                                                                                                                                                                                                                                      int selected = (int)clicked.Tag;
                                                                                                                                                                                                                                                                      QuizQuestion q = quizQuestions[currentQuestionIndex];

                                                                                                                                                                                                                                                                      foreach (var child in QuizOptionsPanel.Children)
                                                                                                                                                                                                                                                                      {
                                                                                                                                                                                                                                                                      if (child is Button btn)
                                                                                                                                                                                                                                                                      {
                                                                                                                                                                                                                                                                      btn.IsEnabled = false;
                                                                                                                                                                                                                                                                      int idx = (int)btn.Tag;
                                                                                                                                                                                                                                                                      if (idx == q.CorrectIndex)
                                                                                                                                                                                                                                                                      {
                                                                                                                                                                                                                                                                      btn.Background = new SolidColorBrush(Color.FromRgb(0x2E, 0x7D, 0x32));
                                                                                                                                                                                                                                                                      btn.Content = "✓ " + q.Options[idx];
                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                      else if (idx == selected)
                                                                                                                                                                                                                                                                      {
                                                                                                                                                                                                                                                                      btn.Background = new SolidColorBrush(Color.FromRgb(0xC6, 0x28, 0x28));
                                                                                                                                                                                                                                                                      btn.Content = "✗ " + q.Options[idx];
                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                      }

                                                                                                                                                                                                                                                                      QuizFeedbackBorder.Visibility = Visibility.Visible;
                                                                                                                                                                                                                                                                      if (selected == q.CorrectIndex)
                                                                                                                                                                                                                                                                      {
                                                                                                                                                                                                                                                                      quizScore++;
                                                                                                                                                                                                                                                                      QuizFeedbackBorder.Background = new SolidColorBrush(Color.FromRgb(0x1B, 0x5E, 0x20));
                                                                                                                                                                                                                                                                      QuizFeedbackBorder.BorderBrush = new SolidColorBrush(Color.FromRgb(0x2E, 0x7D, 0x32));
                                                                                                                                                                                                                                                                      QuizFeedback.Foreground = new SolidColorBrush(Color.FromRgb(0xA5, 0xD6, 0xA7));
                                                                                                                                                                                                                                                                      QuizFeedback.Text = "Correct! " + q.Explanation;
                                                                                                                                                                                                                                                                      LogActivity("Quiz Q" + (currentQuestionIndex + 1) + ": Correct", "Quiz");
                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                      else
                                                                                                                                                                                                                                                                      {
                                                                                                                                                                                                                                                                      QuizFeedbackBorder.Background = new SolidColorBrush(Color.FromRgb(0x4E, 0x1A, 0x1A));
                                                                                                                                                                                                                                                                      QuizFeedbackBorder.BorderBrush = new SolidColorBrush(Color.FromRgb(0xC6, 0x28, 0x28));
                                                                                                                                                                                                                                                                      QuizFeedback.Foreground = new SolidColorBrush(Color.FromRgb(0xFF, 0xCC, 0xBC));
                                                                                                                                                                                                                                                                      QuizFeedback.Text = "Incorrect. Correct answer: " + q.Options[q.CorrectIndex] + "\n" + q.Explanation;
                                                                                                                                                                                                                                                                      LogActivity("Quiz Q" + (currentQuestionIndex + 1) + ": Incorrect", "Quiz");
                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                      QuizScoreLabel.Text = "Score: " + quizScore + "/" + quizQuestions.Count;
                                                                                                                                                                                                                                                                    QuizNextButton.Content = currentQuestionIndex < quizQuestions.Count - 1 ? "Next Question" : "See Results";
                                                                                                                                                                                                                                                                      QuizNextButton.Visibility = Visibility.Visible;
                                                                                                                                                                                                                                                                      }

                                                                                                                                                                                                                                                                      private void QuizNextButton_Click(object sender, RoutedEventArgs e)
                                                                                                                                                                                                                                                                      {
                                                                                                                                                                                                                                                                      currentQuestionIndex++;
                                                                                                                                                                                                                                                                      DisplayQuestion();
                                                                                                                                                                                                                                                                      }

                                                                                                                                                                                                                                                                      private void ShowQuizResults()
                                                                                                                                                                                                                                                                      {
                                                                                                                                                                                                                                                                      QuizPanel.Visibility = Visibility.Collapsed;
                                                                                                                                                                                                                                                                      QuizResultsPanel.Visibility = Visibility.Visible;
                                                                                                                                                                                                                                                                      double pct = (double)quizScore / quizQuestions.Count * 100;
                                                                                                                                                                                                                                                                      QuizResultScore.Text = "Your Score: " + quizScore + "/" + quizQuestions.Count + " (" + Math.Round(pct) + "%)";
                                                                                                                                                                                                                                                                      QuizResultMessage.Text = pct >= 80 ? "Excellent, " + userName + "! You are a cybersecurity pro!" :
                                                                                                                                                                                                                                                                      pct >= 60 ? "Good effort, " + userName + "! Keep strengthening your knowledge." :
                                                                                                                                                                                                                                                                      pct >= 40 ? "You are learning, " + userName + "! Review the topics and try again." :
                                                                                                                                                                                                                                                                                "Keep going, " + userName + "! Every attempt makes you safer online.";
                                                                                                                                                                                                                                                                                LogActivity("Quiz completed — Score: " + quizScore + "/" + quizQuestions.Count + " (" + Math.Round(pct) + "%)", "Quiz");
                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                private void LogActivity(string description, string category)
                                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                                activityLog.Add(new ActivityEntry { Timestamp = DateTime.Now, Description = description, Category = category });
                                                                                                                                                                                                                                                                                RefreshActivityLog();
                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                private void RefreshActivityLog()
                                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                                var recent = activityLog.AsEnumerable().Reverse().Take(activityDisplayCount).ToList();
                                                                                                                                                                                                                                                                                ActivityLogList.ItemsSource = null;
                                                                                                                                                                                                                                                                                ActivityLogList.ItemsSource = recent;
                                                                                                                                                                                                                                                                                ActivityLogCount.Text = "Showing " + recent.Count + " of " + activityLog.Count + " activities";
                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                private string ShowActivityLogInChat()
                                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                                if (activityLog.Count == 0) return "No activities logged yet, " + userName + ".";
                                                                                                                                                                                                                                                                                var recent = activityLog.AsEnumerable().Reverse().Take(5).ToList();
                                                                                                                                                                                                                                                                                LogActivity("User viewed activity log", "Activity");
                                                                                                                                                                                                                                                                                string result = "Here is a summary of recent actions, " + userName + ":\n\n";
                                                                                                                                                                                                                                                                                int c = 1;
                                                                                                                                                                                                                                                                                foreach (var entry in recent)
                                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                                result += c + ". [" + entry.Category + "] " + entry.Description + " (" + entry.Timestamp.ToString("HH:mm") + ")\n";
                                                                                                                                                                                                                                                                                c++;
                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                return result + "\nView the full log in the Activity Log tab!";
                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                private void ShowMoreActivityButton_Click(object sender, RoutedEventArgs e)
                                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                                activityDisplayCount = Math.Min(activityDisplayCount + 5, activityLog.Count);
                                                                                                                                                                                                                                                                                RefreshActivityLog();
                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                private void ClearActivityButton_Click(object sender, RoutedEventArgs e)
                                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                                activityLog.Clear();
                                                                                                                                                                                                                                                                                activityDisplayCount = 8;
                                                                                                                                                                                                                                                                                RefreshActivityLog();
                                                                                                                                                                                                                                                                                responseHandler("Activity log cleared.");
                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                private string GetRandom(string topic)
                                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                                if (!responses.ContainsKey(topic)) return "I don't have information on that yet.";
                                                                                                                                                                                                                                                                                var list = responses[topic];
                                                                                                                                                                                                                                                                                int index;
                                                                                                                                                                                                                                                                                do { index = random.Next(list.Count); }
                                                                                                                                                                                                                                                                      while (list.Count > 1 && lastUsed.ContainsKey(topic) && lastUsed[topic] == index);
                                                                                                                                                                                                                                                                                    lastUsed[topic] = index;
                                                                                                                                                                                                                                                                                    return list[index];
                                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                                    private void DisplayBotMessage(string message)
                                                                                                                                                                                                                                                                                    {
                                                                                                                                                                                                                                                                                    ChatBox.AppendText("CyberBot: " + message + Environment.NewLine + Environment.NewLine);
                                                                                                                                                                                                                                                                                    ChatBox.ScrollToEnd();
                                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                      private void ExitButton_Click(object sender, RoutedEventArgs e) => Application.Current.Shutdown();
                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                        }